int interval_tree(const int *data, int data_len) {
    int n = data[0];
    int query = data[2 * n + 1];
    int count = 0;
    int idx = 1;
    for (int i = 0; i < n; i++) {
        int lo = data[idx], hi = data[idx + 1];
