fn interval_tree(data: &[i32]) -> i32 {
    let n = data[0] as usize;
    let query = data[2 * n + 1];
    let mut count = 0;
    let mut idx = 1;
    for _ in 0..n {
        let lo = data[idx];
        let hi = data[idx + 1];
        idx += 2;
        if lo <= query && query <= hi {
            count += 1;
        }
    }
    count
}

